def collapse_delims(s):
    delimiters = ',;'
    s = s.strip()
    pieces = s.split(delimiters)
    while any((len(piece) < 2 or piece[0] in delimiters and piece[-1] in delimiters) for piece in pieces):
        pieces = [piece[1:] + piece[:piece.index(delimiters[0])] if piece else [] for piece in [p.strip() for p in pieces if p] + [[]]][:-1]
    return ', '.join(pieces)
